on_index:
let res = #{ distance: 0.0 };
let dot_product = 0.0;
let norm_a = 0.0;
let norm_b = 0.0;
for i in 0..16 {
    dot_product += vector_data[i] * query_vector[i];
    norm_a += vector_data[i] * vector_data[i];
    norm_b += query_vector[i] * query_vector[i];
}
if norm_a > 0.0 && norm_b > 0.0 {
    res.distance = dot_product / (sqrt(norm_a) * sqrt(norm_b));
}
res

on_lifecycle:
let res = #{};
if age_ns > config.warm_ttl_ns {
    res.new_tier = "Warm";
    res.clear_payload = true;
}
res
